     1→/**
     2→ * AI Terminal Component
     3→ * Persistent AI assistant with multi-provider chat interface
     4→ *
     5→ * Features:
     6→ * - Multiple AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
     7→ * - Provider/model selection
     8→ * - Automatic fallback on errors
     9→ * - Usage tracking
    10→ * - Encrypted API key storage
    11→ */
    12→
    13→import React, { useState, useRef, useEffect, useMemo } from 'react';
    14→import { useTerminalStore } from '../stores/useTerminalStore';
    15→import { aiTerminalService } from '../services/aiTerminal';
    16→import { createDefaultRouter } from '../services/ai/providerRouter';
    17→import { ProviderSettings } from './ProviderSettings';
    18→import { ModelSelector } from './ModelSelector';
    19→import { UsageTracker } from './UsageTracker';
    20→import ReactMarkdown from 'react-markdown';
    21→import rehypeSanitize, { defaultSchema } from 'rehype-sanitize';
    22→
    23→/**
    24→ * Custom sanitization schema for AI-generated content
    25→ * Extends default schema to allow safe code elements while blocking dangerous ones
    26→ *
    27→ * Security: This prevents XSS attacks from malicious AI responses
    28→ */
    29→const sanitizeSchema = {
    30→  ...defaultSchema,
    31→  tagNames: [
    32→    // Text formatting
    33→    'p', 'br', 'strong', 'em', 'b', 'i', 'u', 's', 'del', 'ins', 'mark',
    34→    // Headings
    35→    'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
    36→    // Lists
    37→    'ul', 'ol', 'li',
    38→    // Code
    39→    'pre', 'code',
    40→    // Quotes & dividers
    41→    'blockquote', 'hr',
    42→    // Links (href will be sanitized)
    43→    'a',
    44→    // Tables
    45→    'table', 'thead', 'tbody', 'tr', 'th', 'td',
    46→    // Other safe elements
    47→    'span', 'div',
    48→  ],
    49→  attributes: {
    50→    ...defaultSchema.attributes,
    51→    a: ['href', 'title', 'target', 'rel'],
    52→    code: ['className'], // For syntax highlighting classes
    53→    pre: ['className'],
    54→    span: ['className'],
    55→    div: ['className'],
    56→  },
    57→  // Force safe link attributes
    58→  protocols: {
    59→    href: ['http', 'https', 'mailto'],
    60→  },
    61→};
    62→
    63→export const AITerminal: React.FC = () => {
    64→  const {
    65→    isOpen,
    66→    apiKey, // Legacy Gemini key
    67→    // model is legacy and unused - destructured but not assigned to avoid TS error
    68→    activeProvider,
    69→    activeModel,
    70→    providers,
    71→    encryptionPassword,
    72→    isPasswordExpired,
    73→    fallbackEnabled,
    74→    messages,
    75→    isStreaming,
    76→    setOpen,
    77→    setActiveProvider,
    78→    addMessage,
    79→    clearMessages,
    80→    setStreaming,
    81→  } = useTerminalStore();
    82→
    83→  const [input, setInput] = useState('');
    84→  const [streamingContent, setStreamingContent] = useState('');
    85→  const [showProviderSettings, setShowProviderSettings] = useState(false);
    86→  const [showModelSelector, setShowModelSelector] = useState(false);
    87→  const [showUsageTracker, setShowUsageTracker] = useState(false);
    88→  const [fallbackNotification, setFallbackNotification] = useState<string | null>(null);
    89→
    90→  const messagesEndRef = useRef<HTMLDivElement>(null);
    91→  const inputRef = useRef<HTMLTextAreaElement>(null);
    92→
    93→  // Initialize provider router
    94→  const [router] = useState(() => createDefaultRouter((failedProvider, _failedModel, nextProvider, nextModel, reason) => {
    95→    // Fallback notification callback
    96→    setFallbackNotification(
    97→      `⚠️ ${failedProvider} failed: ${reason}. Switched to ${nextProvider} (${nextModel}).`
    98→    );
    99→    setTimeout(() => setFallbackNotification(null), 5000);
   100→  }));
   101→
   102→  // Auto-scroll to bottom when messages change
   103→  useEffect(() => {
   104→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   105→  }, [messages, streamingContent]);
   106→
   107→  // Focus input when terminal opens
   108→  useEffect(() => {
   109→    if (isOpen) {
   110→      inputRef.current?.focus();
   111→    }
   112→  }, [isOpen]);
   113→
   114→  // Initialize AI service with API key (legacy Gemini)
   115→  useEffect(() => {
   116→    if (apiKey) {
   117→      aiTerminalService.setApiKey(apiKey);
   118→    }
   119→  }, [apiKey]);
   120→
   121→  // Configure router with active provider and model
   122→  useEffect(() => {
   123→    router.updateConfig({
   124→      primaryProvider: activeProvider,
   125→      primaryModel: activeModel,
   126→      fallbackEnabled: fallbackEnabled,
   127→    });
   128→  }, [activeProvider, activeModel, fallbackEnabled, router]);
   129→
   130→  // Initialize provider API keys from encrypted storage
   131→  useEffect(() => {
   132→    const initializeApiKeys = async () => {
   133→      if (encryptionPassword && !isPasswordExpired()) {
   134→        const allProviders = router.getAllProviders();
   135→        for (const [providerId, provider] of Object.entries(allProviders)) {
   136→          const providerConfig = providers[providerId];
   137→          if (providerConfig && providerConfig.encryptedApiKey) {
   138→            try {
   139→              const decryptedKey = await useTerminalStore.getState().getProviderApiKey(providerId, encryptionPassword);
   140→              if (decryptedKey) {
   141→                provider.setApiKey(decryptedKey);
   142→              }
   143→            } catch (error) {
   144→              console.error(`Failed to decrypt ${providerId} API key:`, error);
   145→            }
   146→          }
   147→        }
   148→      }
   149→    };
   150→
   151→    initializeApiKeys();
   152→  }, [encryptionPassword, isPasswordExpired, providers, router]);
   153→
   154→  // Keyboard shortcuts
   155→  useEffect(() => {
   156→    const handleKeyDown = (e: KeyboardEvent) => {
   157→      // Cmd/Ctrl + Shift + A to toggle terminal
   158→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key.toLowerCase() === 'a') {
   159→        e.preventDefault();
   160→        setOpen(!isOpen);
   161→      }
   162→    };
   163→
   164→    document.addEventListener('keydown', handleKeyDown);
   165→    return () => document.removeEventListener('keydown', handleKeyDown);
   166→  }, [isOpen, setOpen]);
   167→
   168→  const handleSubmit = async (e: React.FormEvent) => {
   169→    e.preventDefault();
   170→    if (!input.trim() || isStreaming) return;
   171→
   172→    const userMessage = input.trim();
   173→    setInput('');
   174→
   175→    // Check if any provider is configured
   176→    const configuredProviders = router.getConfiguredProviders();
   177→    if (configuredProviders.length === 0) {
   178→      addMessage({
   179→        role: 'system',
   180→        content: '⚠️ No AI providers configured. Click the ⚙️ Settings button to add API keys.',
   181→      });
   182→      return;
   183→    }
   184→
   185→    // Check if active provider is configured
   186→    const activeProviderObj = router.getProvider(activeProvider);
   187→    if (!activeProviderObj || !activeProviderObj.isConfigured()) {
   188→      addMessage({
   189→        role: 'system',
   190→        content: `⚠️ Provider "${activeProvider}" is not configured. Please add an API key in Settings.`,
   191→      });
   192→      return;
   193→    }
   194→
   195→    // Add user message
   196→    addMessage({
   197→      role: 'user',
   198→      content: userMessage,
   199→    });
   200→
   201→    // Start streaming
   202→    setStreaming(true);
   203→    setStreamingContent('');
   204→
   205→    try {
   206→      // Send message using router (with automatic fallback)
   207→      const response = await router.sendMessage({
   208→        prompt: userMessage,
   209→        conversationHistory: messages.map((msg) => ({
   210→          role: msg.role as 'user' | 'assistant' | 'system',
   211→          content: msg.content,
   212→        })),
   213→        stream: true,
   214→        onChunk: (chunk) => {
   215→          setStreamingContent((prev) => prev + chunk);
   216→        },
   217→      });
   218→
   219→      // Add complete assistant message with provider/model metadata
   220→      addMessage({
   221→        role: 'assistant',
   222→        content: response.content,
   223→        provider: response.provider || activeProvider,
   224→        model: response.model || activeModel,
   225→      });
   226→    } catch (error) {
   227→      const errorMessage = error instanceof Error ? error.message : 'Unknown error occurred';
   228→      addMessage({
   229→        role: 'system',
   230→        content: `❌ Error: ${errorMessage}`,
   231→      });
   232→    } finally{
   233→      setStreaming(false);
   234→      setStreamingContent('');
   235→    }
   236→  };
   237→
   238→  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
   239→    if (e.key === 'Enter' && !e.shiftKey) {
   240→      e.preventDefault();
   241→      handleSubmit(e);
   242→    }
   243→  };
   244→
   245→  if (!isOpen) return null;
   246→
   247→  return (
   248→    <div
   249→      className={`
   250→        fixed top-0 right-0 h-screen
   251→        transition-transform duration-200 ease-in-out
   252→        ${isOpen ? 'translate-x-0' : 'translate-x-full'}
   253→        w-[300px] lg:w-[375px]
   254→        bg-white dark:bg-black
   255→        border-l border-border-light dark:border-border-dark
   256→        shadow-2xl
   257→        z-40
   258→        flex flex-col
   259→      `}
   260→    >
   261→      {/* Header - Terminal Style */}
   262→      <div className="flex items-center justify-between px-4 py-3 bg-black dark:bg-black text-green-400 border-b border-border-light dark:border-border-dark flex-shrink-0">
   263→        <div className="flex items-center gap-2 font-mono text-sm">
   264→          <span>user@neuman-brain:~$</span>
   265→          <span className="text-green-400 text-xs">
   266→            {router.getConfiguredProviders().length > 0
   267→              ? `${activeProvider}/${activeModel}`
   268→              : 'no-provider'}
   269→          </span>
   270→        </div>
   271→
   272→        <div className="flex items-center gap-1">
   273→          {/* Fallback indicator */}
   274→          {fallbackEnabled && router.getConfiguredProviders().length > 1 && (
   275→            <span className="text-xs bg-green-400/20 px-2 py-0.5 rounded-button font-mono" title="Automatic fallback enabled">
   276→              🔄
   277→            </span>
   278→          )}
   279→
   280→          {/* Usage Tracker */}
   281→          <button
   282→            onClick={() => setShowUsageTracker(!showUsageTracker)}
   283→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   284→            title="Usage Statistics"
   285→            aria-label="View usage statistics"
   286→          >
   287→            📊
   288→          </button>
   289→
   290→          {/* Model Selector */}
   291→          <button
   292→            onClick={() => setShowModelSelector(!showModelSelector)}
   293→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   294→            title="Select Model"
   295→            aria-label="Select AI model"
   296→          >
   297→            🔀
   298→          </button>
   299→
   300→          {/* Provider Settings */}
   301→          <button
   302→            onClick={() => setShowProviderSettings(true)}
   303→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   304→            title="Provider Settings"
   305→            aria-label="Open provider settings"
   306→          >
   307→            ⚙️
   308→          </button>
   309→
   310→          {/* Close */}
   311→          <button
   312→            onClick={() => setOpen(false)}
   313→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-base"
   314→            title="Close Terminal"
   315→            aria-label="Close AI terminal"
   316→          >
   317→            ✕
   318→          </button>
   319→        </div>
   320→      </div>
   321→
   322→      {/* Chat Content */}
   323→      <div className="flex flex-col flex-1 overflow-hidden">
   324→        {/* Messages */}
   325→        <div className="flex-1 overflow-y-auto p-4 space-y-4">
   326→            {/* Fallback Notification */}
   327→            {fallbackNotification && (
   328→              <div className="mb-4 p-3 bg-yellow-100 dark:bg-yellow-900/30 border border-yellow-400 dark:border-yellow-600 rounded-button text-sm text-text-light-primary dark:text-text-dark-primary">
   329→                {fallbackNotification}
   330→              </div>
   331→            )}
   332→
   333→            {messages.length === 0 && router.getConfiguredProviders().length === 0 && (
   334→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   335→                <p className="text-lg font-semibold mb-2">Welcome to AI Terminal!</p>
   336→                <p className="text-sm mb-4">
   337→                  Configure AI providers to get started. Choose from 8 providers including free options!
   338→                </p>
   339→                <button
   340→                  onClick={() => setShowProviderSettings(true)}
   341→                  className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
   342→                >
   343→                  ⚙️ Configure Providers
   344→                </button>
   345→                <div className="mt-4 text-xs space-y-1">
   346→                  <p className="font-medium">Free Providers Available:</p>
   347→                  <p>• OpenRouter (Llama 3.3, Gemini 2.0)</p>
   348→                  <p>• Groq (Lightning-fast inference)</p>
   349→                  <p>• HuggingFace (Thousands of models)</p>
   350→                  <p>• Mistral (European AI)</p>
   351→                </div>
   352→              </div>
   353→            )}
   354→
   355→            {messages.length === 0 && router.getConfiguredProviders().length > 0 && (
   356→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   357→                <p className="text-lg font-semibold mb-2">AI Terminal Ready</p>
   358→                <p className="text-sm mb-2">
   359→                  Active: <span className="font-medium text-accent-blue">{activeProvider}</span> • {activeModel}
   360→                </p>
   361→                <p className="text-sm">Ask me anything! I can help with:</p>
   362→                <ul className="text-sm mt-2 space-y-1">
   363→                  <li>💬 General questions & conversation</li>
   364→                  <li>💻 Code generation & explanation</li>
   365→                  <li>🔧 Debugging & problem solving</li>
   366→                  <li>📝 Writing & productivity</li>
   367→                  <li>🔄 Automatic fallback if provider fails</li>
   368→                </ul>
   369→              </div>
   370→            )}
   371→
   372→            {messages.map((message) => (
   373→              <div
   374→                key={message.id}
   375→                className={`flex gap-3 ${
   376→                  message.role === 'user' ? 'justify-end' : 'justify-start'
