   391→                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400'
   392→                  }`}
   393→                >
   394→                  {message.role === 'assistant' ? (
   395→                    <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   396→                      <ReactMarkdown rehypePlugins={[[rehypeSanitize, sanitizeSchema]]}>
   397→                        {message.content}
   398→                      </ReactMarkdown>
   399→                    </div>
   400→                  ) : (
