   407→                        <span>•</span>
   408→                        <span className="font-medium" title="Provider and model used">
   409→                          {message.provider} • {message.model}
   410→                        </span>
   411→                      </>
   412→                    )}
   413→                  </div>
   414→                </div>
   415→
   416→                {message.role === 'user' && (
