   418→                    👤
   419→                  </div>
   420→                )}
   421→              </div>
   422→            ))}
   423→
   424→            {/* Streaming message */}
   425→            {isStreaming && streamingContent && (
   426→              <div className="flex gap-3 justify-start">
   427→                <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   428→                  🤖
   429→                </div>
   430→                <div className="max-w-[80%] rounded-button px-4 py-2 font-mono bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400">
   431→                  <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   432→                    <ReactMarkdown>{streamingContent}</ReactMarkdown>
   433→                  </div>
   434→                  <div className="flex items-center gap-1 text-xs opacity-60 mt-1">
   435→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse" />
   436→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-75" />
   437→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-150" />
   438→                  </div>
   439→                </div>
   440→              </div>
   441→            )}
   442→
   443→            <div ref={messagesEndRef} />
   444→          </div>
   445→
   446→          {/* Input Area */}
   447→          <div className="border-t border-border-light dark:border-border-dark p-3 bg-surface-light dark:bg-black flex-shrink-0">
   448→            <form onSubmit={handleSubmit} className="flex gap-2">
   449→              <textarea
   450→                ref={inputRef}
   451→                value={input}
   452→                onChange={(e) => setInput(e.target.value)}
   453→                onKeyDown={handleKeyDown}
   454→                placeholder={
   455→                  router.getConfiguredProviders().length > 0
   456→                    ? 'user@neuman-brain:~$ _'
   457→                    : 'Configure providers first...'
   458→                }
   459→                disabled={router.getConfiguredProviders().length === 0 || isStreaming}
   460→                className="flex-1 px-3 py-2 rounded-button font-mono text-sm bg-white dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark text-text-light-primary dark:text-white placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue dark:focus:ring-green-400 focus:border-transparent resize-none"
   461→                rows={1}
   462→              />
   463→              <button
   464→                type="submit"
   465→                disabled={router.getConfiguredProviders().length === 0 || !input.trim() || isStreaming}
   466→                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-neutral-300 dark:disabled:bg-neutral-700 text-white rounded-button font-medium transition-all duration-standard ease-smooth disabled:cursor-not-allowed"
   467→              >
   468→                {isStreaming ? '⋯' : '→'}
   469→              </button>
   470→              {messages.length > 0 && (
   471→                <button
   472→                  type="button"
   473→                  onClick={clearMessages}
   474→                  className="px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark hover:bg-neutral-200 dark:hover:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary rounded-button text-sm transition-all duration-standard ease-smooth"
   475→                  title="Clear chat"
   476→                >
   477→                  🗑️
   478→                </button>
   479→              )}
   480→            </form>
   481→          </div>
   482→        </div>
   483→
   484→      {/* Provider Settings Modal */}
   485→      <ProviderSettings
