   490→
   491→      {/* Model Selector Sliding Panel */}
   492→      {showModelSelector && (
   493→        <div className="absolute top-12 right-0 w-96 max-h-[400px] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden">
