   506→            <ModelSelector
   507→              router={router}
   508→              onSelect={(providerId, modelId) => {
   509→                setActiveProvider(providerId, modelId);
   510→                setShowModelSelector(false);
   511→              }}
   512→              currentProvider={activeProvider}
   513→              currentModel={activeModel}
   514→            />
   515→          </div>
   516→        </div>
   517→      )}
   518→
   519→      {/* Usage Tracker Sliding Panel */}
   520→      {showUsageTracker && (
   521→        <div className="absolute top-12 right-0 w-96 max-h-[500px] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden">
   522→          <div className="p-4 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark">
   523→            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   524→              Usage Tracker
   525→            </h3>
   526→            <button
   527→              onClick={() => setShowUsageTracker(false)}
   528→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded-button"
   529→            >
   530→              ✕
   531→            </button>
   532→          </div>
   533→          <div className="p-4 overflow-y-auto max-h-[450px]">
   534→            <UsageTracker router={router} />
   535→          </div>
   536→        </div>
   537→      )}
   538→    </div>
   539→  );
   540→};
