    28→  failedModel: string,
    29→  nextProvider: string,
    30→  nextModel: string,
    31→  reason: string
    32→) => void;
    33→
    34→/**
    35→ * Provider registry
    36→ */
    37→const PROVIDERS: Record<string, AIProvider> = {
    38→  openrouter: openRouterProvider,
    39→  groq: groqProvider,
    40→  huggingface: huggingFaceProvider,
    41→  mistral: mistralProvider,
    42→  gemini: geminiProvider,
    43→  openai: openaiProvider,
    44→  anthropic: anthropicProvider,
    45→  xai: xaiProvider,
    46→};
    47→
    48→/**
    49→ * Default fallback order (best to worst)
    50→ */
    51→const DEFAULT_FALLBACK_ORDER = [
    52→  'openrouter', // Best flexibility
    53→  'groq', // Best speed
    54→  'huggingface', // Free fallback
    55→  'mistral', // European option
    56→  'gemini', // Google fallback
    57→];
    58→
    59→/**
    60→ * AI Provider Router
    61→ * Manages provider selection and automatic fallbacks
    62→ */
    63→export class AIProviderRouter {
    64→  private config: ProviderRouterConfig;
    65→  private onFallback?: FallbackCallback;
    66→
    67→  constructor(config: ProviderRouterConfig, onFallback?: FallbackCallback) {
    68→    this.config = config;
    69→    this.onFallback = onFallback;
    70→  }
    71→
    72→  /**
    73→   * Update router configuration
    74→   */
    75→  updateConfig(config: Partial<ProviderRouterConfig>): void {
    76→    this.config = { ...this.config, ...config };
    77→  }
    78→
    79→  /**
    80→   * Get provider by ID
    81→   */
    82→  getProvider(providerId: string): AIProvider | null {
    83→    return PROVIDERS[providerId] || null;
    84→  }
    85→
    86→  /**
    87→   * Get all providers
    88→   */
    89→  getAllProviders(): Record<string, AIProvider> {
    90→    return PROVIDERS;
    91→  }
    92→
    93→  /**
    94→   * Get configured providers (those with API keys)
    95→   */
    96→  getConfiguredProviders(): AIProvider[] {
    97→    return Object.values(PROVIDERS).filter((provider) => provider.isConfigured());
    98→  }
    99→
   100→  /**
   101→   * Get primary provider
   102→   */
   103→  getPrimaryProvider(): AIProvider | null {
   104→    return this.getProvider(this.config.primaryProvider);
   105→  }
   106→
   107→  /**
   108→   * Get fallback providers in order
   109→   */
   110→  getFallbackProviders(): AIProvider[] {
   111→    const fallbackOrder = this.config.fallbackOrder.length > 0
   112→      ? this.config.fallbackOrder
   113→      : DEFAULT_FALLBACK_ORDER;
   114→
   115→    return fallbackOrder
   116→      .filter((id) => id !== this.config.primaryProvider) // Exclude primary
   117→      .map((id) => this.getProvider(id))
   118→      .filter((provider): provider is AIProvider => provider !== null && provider.isConfigured());
   119→  }
   120→
   121→  /**
   122→   * Check if a provider error is retryable with fallback
   123→   */
   124→  private isRetryableError(error: ProviderError): boolean {
   125→    // Rate limits and network errors are retryable with different provider
   126→    return (
   127→      error.type === ProviderErrorType.RATE_LIMIT ||
   128→      error.type === ProviderErrorType.QUOTA_EXCEEDED ||
   129→      error.type === ProviderErrorType.NETWORK_ERROR ||
   130→      error.type === ProviderErrorType.TIMEOUT
   131→    );
   132→  }
   133→
   134→  /**
   135→   * Send message with automatic fallback
   136→   */
   137→  async sendMessage(options: AIMessageOptions): Promise<AIResponse> {
   138→    const primaryProvider = this.getPrimaryProvider();
   139→
   140→    if (!primaryProvider) {
   141→      throw new Error(
   142→        `Primary provider "${this.config.primaryProvider}" not found or not configured.`
   143→      );
   144→    }
   145→
   146→    // Try primary provider first
   147→    try {
   148→      const response = await primaryProvider.sendMessage(this.config.primaryModel, options);
   149→      return response;
   150→    } catch (error) {
   151→      // If fallback is disabled, throw immediately
   152→      if (!this.config.fallbackEnabled) {
   153→        throw error;
   154→      }
   155→
   156→      // Check if error is retryable
   157→      if (error instanceof ProviderError && this.isRetryableError(error)) {
   158→        console.warn(
   159→          `Provider ${error.provider} failed with retryable error: ${error.message}. Attempting fallback...`
   160→        );
   161→
   162→        // Try fallback providers
   163→        const fallbackProviders = this.getFallbackProviders();
   164→
   165→        for (const fallbackProvider of fallbackProviders) {
   166→          try {
   167→            // Get default model for fallback provider
   168→            const fallbackModel = fallbackProvider.getDefaultModel();
   169→
   170→            // Notify about fallback
   171→            if (this.config.notifyOnFallback && this.onFallback) {
   172→              this.onFallback(
   173→                this.config.primaryProvider,
   174→                this.config.primaryModel,
   175→                fallbackProvider.metadata.id,
   176→                fallbackModel.id,
   177→                error.message
   178→              );
   179→            }
   180→
   181→            console.log(
   182→              `Falling back to ${fallbackProvider.metadata.name} (${fallbackModel.name})...`
   183→            );
   184→
   185→            // Try fallback provider
   186→            const response = await fallbackProvider.sendMessage(fallbackModel.id, options);
   187→
   188→            // Success! Return response with fallback info
   189→            return {
   190→              ...response,
   191→              provider: fallbackProvider.metadata.id,
   192→              model: fallbackModel.id,
   193→            };
   194→          } catch (fallbackError) {
   195→            console.warn(
   196→              `Fallback provider ${fallbackProvider.metadata.name} also failed:`,
   197→              fallbackError
   198→            );
   199→            // Continue to next fallback
   200→          }
   201→        }
   202→
   203→        // All providers failed
   204→        throw new Error(
   205→          `All providers failed. Primary: ${error.message}. No working fallback found.`
   206→        );
   207→      }
   208→
   209→      // Non-retryable error (invalid API key, model not found, etc.)
   210→      throw error;
   211→    }
   212→  }
   213→
   214→  /**
   215→   * Send message to specific provider (bypass routing)
   216→   */
   217→  async sendMessageToProvider(
   218→    providerId: string,
   219→    modelId: string,
