   232→    return provider.sendMessage(modelId, options);
   233→  }
   234→
   235→  /**
   236→   * Validate all configured providers
   237→   */
   238→  async validateProviders(): Promise<Record<string, boolean>> {
   239→    const results: Record<string, boolean> = {};
   240→
   241→    for (const [id, provider] of Object.entries(PROVIDERS)) {
   242→      if (provider.isConfigured()) {
   243→        const apiKey = provider.getApiKey();
   244→        if (apiKey) {
   245→          try {
   246→            results[id] = await provider.validateApiKey(apiKey);
   247→          } catch (error) {
   248→            results[id] = false;
   249→          }
   250→        } else {
   251→          results[id] = false;
   252→        }
   253→      } else {
   254→        results[id] = false;
   255→      }
   256→    }
   257→
   258→    return results;
   259→  }
   260→
   261→  /**
   262→   * Get provider status summary
   263→   */
   264→  getProviderStatus(): Record<
   265→    string,
   266→    {
   267→      configured: boolean;
   268→      name: string;
   269→      hasFreeModels: boolean;
   270→      modelCount: number;
   271→    }
   272→  > {
   273→    const status: Record<string, any> = {};
   274→
   275→    for (const [id, provider] of Object.entries(PROVIDERS)) {
   276→      status[id] = {
   277→        configured: provider.isConfigured(),
   278→        name: provider.metadata.displayName,
   279→        hasFreeModels: provider.metadata.hasFreeModels,
   280→        modelCount: provider.models.length,
   281→      };
   282→    }
   283→
   284→    return status;
   285→  }
   286→
   287→  /**
   288→   * Get all available models across all configured providers
   289→   */
   290→  getAllAvailableModels(): Array<{
   291→    providerId: string;
   292→    providerName: string;
   293→    model: any;
   294→  }> {
   295→    const models: any[] = [];
   296→
   297→    for (const [id, provider] of Object.entries(PROVIDERS)) {
   298→      if (provider.isConfigured()) {
   299→        provider.models.forEach((model) => {
   300→          models.push({
   301→            providerId: id,
   302→            providerName: provider.metadata.displayName,
   303→            model: model,
   304→          });
   305→        });
   306→      }
   307→    }
   308→
   309→    return models;
   310→  }
   311→
   312→  /**
   313→   * Get free models across all configured providers
   314→   */
   315→  getFreeModels(): Array<{
   316→    providerId: string;
   317→    providerName: string;
   318→    model: any;
   319→  }> {
   320→    return this.getAllAvailableModels().filter((item) => item.model.isFree);
   321→  }
   322→
   323→  /**
   324→   * Recommend best provider for a given use case
   325→   */
   326→  recommendProvider(useCase: string, requireFree: boolean = false): {
   327→    providerId: string;
   328→    modelId: string;
   329→  } | null {
   330→    const configuredProviders = this.getConfiguredProviders();
   331→
   332→    if (configuredProviders.length === 0) {
   333→      return null;
   334→    }
   335→
   336→    // Filter by use case and free requirement
   337→    for (const provider of configuredProviders) {
   338→      const suitableModels = provider.models.filter((model) => {
   339→        const matchesUseCase = model.useCases.includes(useCase);
   340→        const matchesFreeRequirement = !requireFree || model.isFree;
   341→        return matchesUseCase && matchesFreeRequirement;
   342→      });
   343→
   344→      if (suitableModels.length > 0) {
   345→        // Sort by quality rating (descending)
   346→        suitableModels.sort((a, b) => b.qualityRating - a.qualityRating);
   347→
   348→        return {
   349→          providerId: provider.metadata.id,
   350→          modelId: suitableModels[0].id,
   351→        };
   352→      }
   353→    }
   354→
   355→    // No suitable model found, return default
   356→    const defaultProvider = configuredProviders[0];
   357→    return {
   358→      providerId: defaultProvider.metadata.id,
   359→      modelId: defaultProvider.getDefaultModel().id,
   360→    };
   361→  }
   362→}
   363→
   364→/**
   365→ * Create default router instance
   366→ */
   367→export function createDefaultRouter(onFallback?: FallbackCallback): AIProviderRouter {
   368→  const config: ProviderRouterConfig = {
   369→    primaryProvider: 'openrouter',
   370→    primaryModel: 'meta-llama/llama-3.3-70b-instruct:free',
   371→    fallbackEnabled: true,
   372→    fallbackOrder: DEFAULT_FALLBACK_ORDER,
   373→    notifyOnFallback: true,
   374→  };
   375→
   376→  return new AIProviderRouter(config, onFallback);
   377→}
