/**
 * Error Notifications Hook
 * Connects the error service to React components for displaying error toasts
 */

import { useState, useEffect, useCallback } from 'react';
import { errorService, AppError, ErrorSeverity } from '../services/errorService';

interface ErrorNotification extends AppError {
  /** Whether the notification is visible */
  visible: boolean;
}

/**
 * Hook to manage error notifications in React components
 */
export function useErrorNotifications(maxVisible: number = 3) {
  const [notifications, setNotifications] = useState<ErrorNotification[]>([]);

  // Subscribe to error service
  useEffect(() => {
    const unsubscribe = errorService.subscribe((error) => {
      const notification: ErrorNotification = {
        ...error,
        visible: true,
      };

      setNotifications((prev) => {
        // Add new notification, limit to maxVisible
        const updated = [...prev, notification].slice(-maxVisible);
        return updated;
      });

      // Auto-dismiss non-critical errors
      if (error.severity !== ErrorSeverity.CRITICAL) {
        const timeout = errorService.getAutoDismissTimeout();
        setTimeout(() => {
          dismissNotification(error.id);
        }, timeout);
      }
    });

    return unsubscribe;
  }, [maxVisible]);

  // Dismiss a notification
  const dismissNotification = useCallback((errorId: string) => {
    setNotifications((prev) =>
      prev.map((n) => (n.id === errorId ? { ...n, visible: false } : n))
    );

    // Remove from array after animation
    setTimeout(() => {
      setNotifications((prev) => prev.filter((n) => n.id !== errorId));
    }, 300);
  }, []);

  // Dismiss all notifications
  const dismissAll = useCallback(() => {
    setNotifications((prev) => prev.map((n) => ({ ...n, visible: false })));
    setTimeout(() => {
      setNotifications([]);
    }, 300);
  }, []);

  // Get visible notifications only
  const visibleNotifications = notifications.filter((n) => n.visible);

  return {
    notifications: visibleNotifications,
    dismissNotification,
    dismissAll,
    hasNotifications: visibleNotifications.length > 0,
  };
}

/**
 * Error Toast Component
 * Displays error notifications from the error service
 */

import React from 'react';
import { useErrorNotifications } from '../hooks/useErrorNotifications';
import { ErrorSeverity } from '../services/errorService';

/**
 * Get icon based on severity
 */
function getSeverityIcon(severity: ErrorSeverity): string {
  switch (severity) {
    case ErrorSeverity.INFO:
      return 'ℹ️';
    case ErrorSeverity.WARNING:
      return '⚠️';
    case ErrorSeverity.ERROR:
      return '❌';
    case ErrorSeverity.CRITICAL:
      return '🚨';
    default:
      return '❌';
  }
}

/**
 * Get background color based on severity
 */
function getSeverityClasses(severity: ErrorSeverity): string {
  switch (severity) {
    case ErrorSeverity.INFO:
      return 'bg-blue-50 dark:bg-blue-900/30 border-blue-200 dark:border-blue-700';
    case ErrorSeverity.WARNING:
      return 'bg-yellow-50 dark:bg-yellow-900/30 border-yellow-200 dark:border-yellow-700';
    case ErrorSeverity.ERROR:
      return 'bg-red-50 dark:bg-red-900/30 border-red-200 dark:border-red-700';
    case ErrorSeverity.CRITICAL:
      return 'bg-red-100 dark:bg-red-900/50 border-red-300 dark:border-red-600';
    default:
      return 'bg-red-50 dark:bg-red-900/30 border-red-200 dark:border-red-700';
  }
}

/**
 * Error Toast Container
 * Renders all active error notifications
 */
export const ErrorToastContainer: React.FC = () => {
  const { notifications, dismissNotification } = useErrorNotifications();

  if (notifications.length === 0) {
    return null;
  }

  return (
    <div
      className="fixed bottom-4 right-4 z-50 flex flex-col gap-2 max-w-sm"
      role="region"
      aria-label="Notifications"
      aria-live="polite"
    >
      {notifications.map((notification) => (
        <div
          key={notification.id}
          className={`
            ${getSeverityClasses(notification.severity)}
            border rounded-button p-4 shadow-lg
            transform transition-all duration-300 ease-smooth
            ${notification.visible ? 'translate-x-0 opacity-100' : 'translate-x-full opacity-0'}
          `}
          role="alert"
        >
          <div className="flex items-start gap-3">
            <span className="text-xl flex-shrink-0" aria-hidden="true">
              {getSeverityIcon(notification.severity)}
            </span>

            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
                {notification.userMessage}
              </p>

              {notification.recoveryAction && notification.severity === ErrorSeverity.CRITICAL && (
                <p className="mt-1 text-xs text-text-light-secondary dark:text-text-dark-secondary">
                  {notification.recoveryAction}
                </p>
              )}
            </div>

            <button
              onClick={() => dismissNotification(notification.id)}
              className="flex-shrink-0 p-1 rounded-button hover:bg-black/10 dark:hover:bg-white/10 transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent-blue"
              aria-label="Dismiss notification"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

