    92→    // Sort keys and process values
    93→    const sorted: Record<string, any> = {};
    94→    const keys = Object.keys(obj).sort();
    95→
    96→    for (const key of keys) {
    97→      const value = optimizeForCompression(obj[key]);
    98→      // Only include non-empty values
    99→      if (value !== null && value !== undefined) {
   100→        if (typeof value === 'object' && !Array.isArray(value) && Object.keys(value).length === 0) {
   101→          continue; // Skip empty objects
   102→        }
   103→        if (Array.isArray(value) && value.length === 0) {
   104→          continue; // Skip empty arrays
   105→        }
   106→        sorted[key] = value;
   107→      }
   108→    }
   109→
   110→    return sorted;
   111→  }
   112→
   113→  return obj;
   114→};
