   350→ * Auto-save to a user-selected directory using File System Access API
   351→ * Uses single file + hidden versioning strategy:
   352→ * - Main file: User's custom filename (e.g., "Neuman.Brain") - always overwritten
   353→ * - Versions: Hidden .neuman-backups/ folder with timestamped backups
   354→ * - Auto-cleanup: Keeps only last N versions (user configurable)
   355→ */
   356→export const autoSave = async (directoryHandle: FileSystemDirectoryHandle): Promise<ExportResult> => {
   357→  try {
   358→    // Load preferences for custom filename and version count
   359→    const { loadPreferences } = await import('./backupPreferences');
   360→    const preferences = await loadPreferences();
   361→    const customFilename = preferences.customFilename || 'Neuman.Brain';
   362→    const versionCount = preferences.versionCount || 7;
   363→
