   381→    };
   382→
   383→    // Optimize for compression (sorts keys, removes empty values)
   384→    const optimizedBackup = optimizeForCompression(backup);
   385→    const jsonString = JSON.stringify(optimizedBackup);
   386→    const compressedBlob = await compressData(jsonString);
   387→
   388→    // 1. Write/overwrite main file with custom filename
   389→    const mainFileHandle = await directoryHandle.getFileHandle(customFilename, { create: true });
   390→    const mainWritable = await mainFileHandle.createWritable();
   391→    await mainWritable.write(compressedBlob);
   392→    await mainWritable.close();
   393→
   394→    console.log(`✅ Main file saved: ${customFilename}`);
   395→
   396→    // 2. Create hidden .neuman-backups folder for versioning
   397→    const backupFolderHandle = await directoryHandle.getDirectoryHandle('.neuman-backups', { create: true });
   398→
   399→    // 3. Save versioned backup with timestamp
   400→    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5);
   401→    const versionFilename = `backup-${timestamp}.brain`;
   402→    const versionFileHandle = await backupFolderHandle.getFileHandle(versionFilename, { create: true });
   403→    const versionWritable = await versionFileHandle.createWritable();
   404→    await versionWritable.write(compressedBlob);
   405→    await versionWritable.close();
   406→
   407→    console.log(`✅ Version saved: .neuman-backups/${versionFilename}`);
   408→
   409→    // 4. Auto-cleanup old versions
   410→    try {
   411→      const versions: { name: string; timestamp: number }[] = [];
   412→      // @ts-ignore - TypeScript doesn't have proper types for FileSystemDirectoryHandle iteration
   413→      for await (const entry of backupFolderHandle.values()) {
   414→        if (entry.kind === 'file' && entry.name.startsWith('backup-') && entry.name.endsWith('.brain')) {
   415→          // Extract timestamp from filename
   416→          const file = await entry.getFile();
   417→          versions.push({
   418→            name: entry.name,
   419→            timestamp: file.lastModified,
   420→          });
   421→        }
   422→      }
   423→
   424→      // Sort by timestamp (newest first)
   425→      versions.sort((a, b) => b.timestamp - a.timestamp);
   426→
   427→      // Delete versions beyond the keep count
   428→      if (versions.length > versionCount) {
   429→        const toDelete = versions.slice(versionCount);
