   433→        }
   434→      }
   435→    } catch (cleanupError) {
   436→      console.warn('Failed to cleanup old versions:', cleanupError);
   437→      // Don't fail the entire save if cleanup fails
   438→    }
   439→
   440→    console.log(`✅ Auto-save complete: ${customFilename} (${versionCount} versions kept)`);
   441→
   442→    return {
   443→      filename: customFilename,
   444→      size: compressedBlob.size,
   445→      compressed: true,
   446→    };
   447→  } catch (error) {
   448→    console.error('Auto-save failed:', error);
   449→    throw new Error(`Auto-save failed: ${error}`);
   450→  }
   451→};
