      } catch (decompError) {
        throw new Error('Invalid .brain file: Not valid JSON or compressed data');
      }
    }

    // Parse JSON
    let backup: BrainBackup;
    try {
      backup = JSON.parse(fileContent);
    } catch (error) {
      throw new Error('Invalid .brain file: Not valid JSON');
    }

