    if (!backup.version || !backup.data) {
      throw new Error('Invalid .brain file: Missing required fields');
    }

    // Version compatibility check
    if (backup.version !== BACKUP_VERSION) {
      console.warn(`Backup version mismatch: ${backup.version} vs ${BACKUP_VERSION}`);
      // For now, continue anyway - can add migration logic later
    }

    // Import all data to IndexedDB using batch operations (50-100x faster)
    const itemsToImport: Record<string, string> = {};
    for (const [key, value] of Object.entries(backup.data)) {
      // Convert back to JSON string for storage
      const jsonString = typeof value === 'string' ? value : JSON.stringify(value);
