      if (versions.length > versionCount) {
        const toDelete = versions.slice(versionCount);
        for (const old of toDelete) {
          await backupFolderHandle.removeEntry(old.name);
          console.log(`🗑️ Deleted old version: ${old.name}`);
        }
      }
