    throw new Error(`Failed to save directory handle: ${error}`);
  }
};

/**
 * Retrieve directory handle from IndexedDB
 * Verifies permissions and re-requests if needed
 */
export const getDirectoryHandle = async (): Promise<FileSystemDirectoryHandle | null> => {
  try {
    // Retrieve handle from IndexedDB
    const handle = await indexedDBService.getObject<FileSystemDirectoryHandle>('auto-save-directory-handle-obj');

    if (!handle) {
      console.log('No saved directory handle found');
      return null;
    }

    // Verify permission (TypeScript type definitions may be incomplete)
    const permission = await (handle as any).queryPermission({ mode: 'readwrite' });

    if (permission === 'granted') {
      console.log('✅ Restored directory handle with granted permission');
      return handle;
    }

    // Permission not granted, try to request it
    console.log('⚠️ Permission not granted, requesting...');
    const newPermission = await (handle as any).requestPermission({ mode: 'readwrite' });

    if (newPermission === 'granted') {
      console.log('✅ Permission granted after request');
      return handle;
    }

    // Permission denied
    console.warn('❌ Permission denied for saved directory');
    return null;
  } catch (error) {
    console.error('Failed to restore directory handle:', error);
    return null;
  }
};

