import { logger } from './logger';

const log = logger.module('IndexedDB');

const DB_NAME = 'neuman-brain-db';
const DB_VERSION = 1;
const STORE_NAME = 'brain-data';

interface DBConnection {
  db: IDBDatabase | null;
  isReady: boolean;
