   154→/**
   155→ * Sort notes based on sort config
   156→ */
   157→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   158→  const sorted = [...notes];
   159→
   160→  sorted.sort((a, b) => {
   161→    let comparison = 0;
   162→
   163→    switch (config.field) {
   164→      case 'title':
   165→        comparison = a.title.localeCompare(b.title);
   166→        break;
   167→      case 'createdAt':
   168→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   169→        break;
   170→      case 'updatedAt':
   171→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   172→        break;
   173→      case 'manual':
   174→        // Manual sort - preserve order (could add sortOrder field in future)
   175→        comparison = 0;
   176→        break;
   177→    }
   178→
   179→    return config.order === 'asc' ? comparison : -comparison;
   180→  });
   181→
   182→  // Always pin pinned notes to top
   183→  return sorted.sort((a, b) => {
   184→    if (a.isPinned && !b.isPinned) return -1;
   185→    if (!a.isPinned && b.isPinned) return 1;
   186→    return 0;
   187→  });
   188→};
