  // Actions - Utility
  getNoteCount: () => number;
  getNotesInFolder: (folderId: string | null) => Note[];
  exportNotes: () => Note[];
  importNotes: (notes: Note[], merge: boolean) => void;
  clearAllNotes: () => void;

  // Actions - Backlinks (Phase 4)
  getBacklinks: (noteId: string) => Note[];
  updateLinkedNotes: (noteId: string, content: string) => void;

  // Actions - Templates (Phase 4)
  getNoteTemplates: () => NoteTemplate[];
  createNoteFromTemplate: (templateId: string) => Note | null;
}

/**
 * Default note values
 */
const createDefaultNote = (overrides?: Partial<Note>): Note => {
  const now = new Date();
  return {
    id: uuidv4(),
    folderId: null,
    title: NOTE_CONSTANTS.DEFAULT_TITLE,
    content: '', // Empty Lexical state
    contentText: '',
    tags: [],
    createdAt: now,
    updatedAt: now,
    isPinned: false,
    isArchived: false,
    ...overrides,
  };
};

/**
 * Sort notes based on sort config
 */
const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
  const sorted = [...notes];

  sorted.sort((a, b) => {
    let comparison = 0;

    switch (config.field) {
      case 'title':
        comparison = a.title.localeCompare(b.title);
        break;
      case 'createdAt':
        comparison = a.createdAt.getTime() - b.createdAt.getTime();
        break;
      case 'updatedAt':
        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
        break;
      case 'manual':
        // Manual sort - preserve order (could add sortOrder field in future)
        comparison = 0;
        break;
    }

    return config.order === 'asc' ? comparison : -comparison;
  });

  // Always pin pinned notes to top
  return sorted.sort((a, b) => {
    if (a.isPinned && !b.isPinned) return -1;
    if (!a.isPinned && b.isPinned) return 1;
    return 0;
  });
};

/**
 * Filter notes based on filter type
 */
const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
  switch (filter) {
    case 'favorites':
      return notes.filter((note) => note.isFavorite);
    case 'pinned':
      return notes.filter((note) => note.isPinned);
    case 'archived':
      return notes.filter((note) => note.isArchived);
    case 'unarchived':
      return notes.filter((note) => !note.isArchived);
    case 'all':
    default:
      return notes;
  }
};

/**
 * Create the Notes store
 */
export const useNotesStore = create<NotesStore>()(
  persist(
    (set, get) => ({
      // Initial state
      notes: {},
      activeNoteId: null,
      sortConfig: {
        field: 'updatedAt',
        order: 'desc',
      },
      filter: 'unarchived',

      // CRUD Operations
      createNote: (params) => {
        const newNote = createDefaultNote(params);
        set((state) => ({
          notes: {
            ...state.notes,
            [newNote.id]: newNote,
          },
          activeNoteId: newNote.id, // Auto-select new note
        }));
        console.log('✅ Note created:', newNote.id);
        return newNote;
      },

      getNote: (id) => {
        return get().notes[id];
      },

      updateNote: (id, updates) => {
        const note = get().notes[id];
        if (!note) {
          console.warn(`Note ${id} not found`);
          return;
        }

        // Only update timestamp if content/title/tags actually changed
        // Skip timestamp update for UI-only changes (like folderId without content change)
        const shouldUpdateTimestamp =
          updates.content !== undefined ||
          updates.title !== undefined ||
          updates.tags !== undefined;

        set((state) => ({
          notes: {
            ...state.notes,
            [id]: {
              ...note,
              ...updates,
              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
            },
          },
        }));
        console.log('✅ Note updated:', id, shouldUpdateTimestamp ? '(timestamp updated)' : '(no timestamp change)');
      },

      deleteNote: (id) => {
        // Save note for undo
        const noteToDelete = get().notes[id];
        if (!noteToDelete) {
          console.warn(`Note ${id} not found`);
          return;
        }

        // Store the previous activeNoteId for undo
        const wasActive = get().activeNoteId === id;

        // Delete the note
        set((state) => {
          const { [id]: deleted, ...remainingNotes } = state.notes;
          return {
            notes: remainingNotes,
            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
          };
        });

        console.log('✅ Note deleted:', id);

        // Delete associated images from IndexedDB (async, fire-and-forget)
        import('../services/indexedDB').then(({ indexedDBService }) => {
          indexedDBService.deleteNoteImages(id).catch((err) => {
            console.error('Failed to delete note images:', err);
          });
        });

        // Add undo action
        useUndoStore.getState().addUndoAction(
          `Note "${noteToDelete.title}" deleted`,
          () => {
            // Restore the note
            set((state) => ({
              notes: {
                ...state.notes,
                [id]: noteToDelete,
              },
              activeNoteId: wasActive ? id : state.activeNoteId,
            }));
            console.log('✅ Note restored (undo):', id);
          }
        );
      },

      duplicateNote: (id) => {
        const original = get().notes[id];
        if (!original) {
          console.warn(`Note ${id} not found`);
          return null;
        }

        const duplicate = createDefaultNote({
          ...original,
          title: `${original.title} (Copy)`,
          isPinned: false, // Don't copy pin status
        });

        set((state) => ({
          notes: {
            ...state.notes,
            [duplicate.id]: duplicate,
          },
        }));

        console.log('✅ Note duplicated:', id, '→', duplicate.id);
        return duplicate;
      },

      // Bulk operations
      deleteNotes: (ids) => {
        set((state) => {
          const remainingNotes = { ...state.notes };
          ids.forEach((id) => delete remainingNotes[id]);
          return {
            notes: remainingNotes,
            activeNoteId: ids.includes(state.activeNoteId || '')
              ? null
              : state.activeNoteId,
          };
        });
        console.log(`✅ Deleted ${ids.length} notes`);

        // Delete associated images from IndexedDB (async, fire-and-forget)
        import('../services/indexedDB').then(({ indexedDBService }) => {
          ids.forEach((id) => {
            indexedDBService.deleteNoteImages(id).catch((err) => {
              console.error(`Failed to delete images for note ${id}:`, err);
            });
          });
        });
      },

      moveNotesToFolder: (noteIds, folderId) => {
        set((state) => {
          const updatedNotes = { ...state.notes };
          noteIds.forEach((id) => {
            if (updatedNotes[id]) {
              updatedNotes[id] = {
                ...updatedNotes[id],
                folderId,
                updatedAt: new Date(),
              };
            }
          });
          return { notes: updatedNotes };
        });
        console.log(`✅ Moved ${noteIds.length} notes to folder:`, folderId);
      },

      archiveNotes: (noteIds) => {
        set((state) => {
          const updatedNotes = { ...state.notes };
          noteIds.forEach((id) => {
            if (updatedNotes[id]) {
              updatedNotes[id] = {
                ...updatedNotes[id],
                isArchived: true,
                updatedAt: new Date(),
              };
            }
          });
          return { notes: updatedNotes };
        });
        console.log(`✅ Archived ${noteIds.length} notes`);
      },

      unarchiveNotes: (noteIds) => {
        set((state) => {
          const updatedNotes = { ...state.notes };
          noteIds.forEach((id) => {
            if (updatedNotes[id]) {
              updatedNotes[id] = {
                ...updatedNotes[id],
                isArchived: false,
                updatedAt: new Date(),
              };
            }
          });
          return { notes: updatedNotes };
        });
        console.log(`✅ Unarchived ${noteIds.length} notes`);
      },

      // Queries
      getAllNotes: () => {
        const state = get();
        const notes = Object.values(state.notes);
        const filtered = filterNotes(notes, state.filter);
        return sortNotes(filtered, state.sortConfig);
      },

      getNotesByFolder: (folderId) => {
        const state = get();
        const notes = Object.values(state.notes).filter(
          (note) => note.folderId === folderId
        );
        const filtered = filterNotes(notes, state.filter);
        return sortNotes(filtered, state.sortConfig);
      },

      getNotesBy: (predicate) => {
        const notes = Object.values(get().notes).filter(predicate);
        return sortNotes(notes, get().sortConfig);
      },

      searchNotes: (query) => {
        if (!query.trim()) return [];

        const lowerQuery = query.toLowerCase();
        const notes = Object.values(get().notes).filter((note) => {
          // Search in title, content text, and tags
          return (
            note.title.toLowerCase().includes(lowerQuery) ||
            note.contentText.toLowerCase().includes(lowerQuery) ||
            note.tags.some((tag) => tag.toLowerCase().includes(lowerQuery))
          );
        });

        return sortNotes(notes, get().sortConfig);
      },

      // Pin/Archive
      togglePin: (id) => {
        const note = get().notes[id];
        if (!note) return;

        set((state) => ({
          notes: {
            ...state.notes,
            [id]: {
              ...note,
              isPinned: !note.isPinned,
              updatedAt: new Date(),
            },
          },
        }));
        console.log(`✅ Toggled pin for note: ${id} (${!note.isPinned})`);
      },

      toggleArchive: (id) => {
        const note = get().notes[id];
        if (!note) return;

        set((state) => ({
          notes: {
            ...state.notes,
            [id]: {
              ...note,
              isArchived: !note.isArchived,
              updatedAt: new Date(),
            },
          },
        }));
        console.log(`✅ Toggled archive for note: ${id} (${!note.isArchived})`);
      },

      toggleFavorite: (id) => {
        const note = get().notes[id];
        if (!note) return;

        set((state) => ({
          notes: {
            ...state.notes,
            [id]: {
              ...note,
              isFavorite: !note.isFavorite,
              updatedAt: new Date(),
            },
          },
        }));
        console.log(`✅ Toggled favorite for note: ${id} (${!note.isFavorite})`);
      },

      // Tags
      addTag: (id, tag) => {
        const note = get().notes[id];
        if (!note) return;

        // Don't add duplicate tags
        if (note.tags.includes(tag)) return;

        // Check max tags limit
        if (note.tags.length >= NOTE_CONSTANTS.MAX_TAGS) {
          console.warn(`Max tags (${NOTE_CONSTANTS.MAX_TAGS}) reached`);
          return;
        }

        set((state) => ({
          notes: {
            ...state.notes,
            [id]: {
              ...note,
              tags: [...note.tags, tag],
              updatedAt: new Date(),
            },
          },
        }));
        console.log(`✅ Added tag "${tag}" to note: ${id}`);
      },

      removeTag: (id, tag) => {
        const note = get().notes[id];
        if (!note) return;

        set((state) => ({
          notes: {
            ...state.notes,
            [id]: {
              ...note,
              tags: note.tags.filter((t) => t !== tag),
              updatedAt: new Date(),
            },
          },
        }));
        console.log(`✅ Removed tag "${tag}" from note: ${id}`);
      },

      getAllTags: () => {
        const notes = Object.values(get().notes);
        const tagSet = new Set<string>();
        notes.forEach((note) => {
          note.tags.forEach((tag) => tagSet.add(tag));
        });
        return Array.from(tagSet).sort();
      },

      // UI state
      setActiveNote: (id) => {
        set({ activeNoteId: id });
        console.log('✅ Active note set:', id);
      },

      setSortConfig: (config) => {
        set({ sortConfig: config });
        console.log('✅ Sort config updated:', config);
      },

      setFilter: (filter) => {
        set({ filter });
        console.log('✅ Filter updated:', filter);
      },

      // Utility
      getNoteCount: () => {
        return Object.keys(get().notes).length;
      },

      getNotesInFolder: (folderId) => {
        return Object.values(get().notes).filter(
          (note) => note.folderId === folderId
        );
      },

      exportNotes: () => {
        return Object.values(get().notes);
      },

      importNotes: (notes, merge) => {
        if (!merge) {
          // Replace all notes
          set({
            notes: Object.fromEntries(notes.map((note) => [note.id, note])),
            activeNoteId: null,
          });
          console.log(`✅ Imported ${notes.length} notes (replace mode)`);
        } else {
          // Merge with existing notes
          set((state) => {
            const updatedNotes = { ...state.notes };
            notes.forEach((note) => {
              updatedNotes[note.id] = note;
            });
            return { notes: updatedNotes };
          });
          console.log(`✅ Imported ${notes.length} notes (merge mode)`);
        }
      },

      clearAllNotes: () => {
        set({ notes: {}, activeNoteId: null });
        console.log('✅ All notes cleared');
      },

      // ==================== BACKLINKS (Phase 4) ====================

      getBacklinks: (noteId: string) => {
        const state = get();
        const note = state.notes[noteId];
        if (!note) return [];

        return getBacklinksUtil(noteId, note.title, state.notes);
      },

      updateLinkedNotes: (noteId: string, content: string) => {
        const state = get();
        const linkTitles = extractWikiLinks(content);
        const linkedNoteIds = resolveLinksToIds(linkTitles, state.notes);

        set((currentState) => {
          const note = currentState.notes[noteId];
          if (!note) return currentState;

          return {
            notes: {
              ...currentState.notes,
              [noteId]: {
                ...note,
                linkedNotes: linkedNoteIds,
              },
            },
          };
        });
      },

      // ==================== TEMPLATES (Phase 4) ====================

      getNoteTemplates: () => {
        return DEFAULT_NOTE_TEMPLATES;
      },

      createNoteFromTemplate: (templateId: string) => {
        const template = DEFAULT_NOTE_TEMPLATES.find((t) => t.id === templateId);
        if (!template) return null;

        const newNote = createDefaultNote({
          title: template.name,
          contentText: template.description,
          tags: template.defaultTags || [],
          icon: template.icon,
        });

        set((state) => ({
          notes: {
            ...state.notes,
            [newNote.id]: newNote,
          },
          activeNoteId: newNote.id,
        }));

        console.log(`✅ Created note from template: ${template.name}`);
        return newNote;
      },
    }),
    {
      name: 'notes', // IndexedDB key
      storage: createJSONStorage(() => createSyncedStorage()),
      partialize: (state) => ({
        // Only persist notes, not UI state
        notes: state.notes,
      }),
      // Handle date serialization
      onRehydrateStorage: () => (state) => {
        console.log('🔄 Notes store rehydrating...', state);
        if (state) {
          try {
            // Ensure notes object exists and is valid
            if (state.notes && typeof state.notes === 'object') {
              // Convert date strings back to Date objects
              Object.values(state.notes).forEach((note) => {
                if (typeof note.createdAt === 'string') {
                  note.createdAt = new Date(note.createdAt);
                }
                if (typeof note.updatedAt === 'string') {
                  note.updatedAt = new Date(note.updatedAt);
                }
              });
            } else {
              console.warn('⚠️ Corrupted notes data detected, resetting to empty');
              state.notes = {};
            }
          } catch (err) {
            console.error('❌ Error during notes store rehydration:', err);
            // Reset to safe defaults
            state.notes = {};
            state.activeNoteId = null;
          }
        }
        console.log('✅ Notes store rehydrated', state);
      },
    }
  )
);

/**
 * Selector hooks for optimized re-renders
 */
export const useActiveNote = () =>
  useNotesStore((state) => {
    const activeId = state.activeNoteId;
    return activeId ? state.notes[activeId] : null;
  });

export const useNotesByFolder = (folderId: string | null) =>
  useNotesStore((state) => state.getNotesByFolder(folderId));

export const useAllTags = () => useNotesStore((state) => state.getAllTags());

