  log.debug('Toggled archive', { id, isArchived: !note.isArchived });
},

toggleFavorite: (id) => {
  const note = get().notes[id];
  if (!note) return;

  set((state) => ({
    notes: {
      ...state.notes,
      [id]: {
        ...note,
        isFavorite: !note.isFavorite,
        updatedAt: new Date(),
      },
    },
  }));
  log.debug('Toggled favorite', { id, isFavorite: !note.isFavorite });
},

