    67→/**
    68→ * Default folder values
    69→ */
    70→const createDefaultFolder = (overrides?: Partial<Folder>): Folder => {
    71→  const now = new Date();
    72→  return {
    73→    id: uuidv4(),
    74→    parentId: null,
    75→    name: FOLDER_CONSTANTS.DEFAULT_NAME,
    76→    createdAt: now,
    77→    updatedAt: now,
    78→    isExpanded: true, // New folders expanded by default
    79→    ...overrides,
    80→  };
    81→};
    82→
    83→/**
    84→ * Build tree structure from flat folder list
    85→ */
    86→const buildTree = (
    87→  folders: Folder[],
    88→  parentId: string | null,
    89→  depth: number = 0,
    90→  notesCountMap: Record<string, number> = {}
    91→): FolderTreeNode[] => {
    92→  const children = folders.filter((f) => f.parentId === parentId);
    93→
    94→  return children.map((folder) => {
    95→    const subtree = buildTree(folders, folder.id, depth + 1, notesCountMap);
    96→    const noteCount = notesCountMap[folder.id] || 0;
    97→    const totalNoteCount =
    98→      noteCount + subtree.reduce((sum, child) => sum + child.totalNoteCount, 0);
    99→
   100→    return {
   101→      ...folder,
   102→      children: subtree,
   103→      depth,
   104→      path: [], // Will be filled in by getPath if needed
   105→      noteCount,
   106→      totalNoteCount,
   107→    };
   108→  });
   109→};
