   130→            `Max folder depth (${FOLDER_CONSTANTS.MAX_DEPTH}) reached`
   131→          );
   132→          return newFolder; // Return but don't create
   133→        }
   134→
   135→        set((state) => ({
   136→          folders: {
   137→            ...state.folders,
   138→            [newFolder.id]: newFolder,
   139→          },
   140→          expandedFolderIds: new Set([
   141→            ...state.expandedFolderIds,
   142→            newFolder.id,
   143→          ]),
   144→          activeFolderId: newFolder.id, // Auto-select new folder
   145→        }));
   146→
   147→        // Expand parent folder if it exists
   148→        if (newFolder.parentId) {
   149→          get().expandFolder(newFolder.parentId);
   150→        }
   151→
   152→        console.log('✅ Folder created:', newFolder.id);
   153→        return newFolder;
   154→      },
   155→
   156→      getFolder: (id) => {
   157→        return get().folders[id];
   158→      },
   159→
   160→      updateFolder: (id, updates) => {
   161→        const folder = get().folders[id];
   162→        if (!folder) {
   163→          console.warn(`Folder ${id} not found`);
   164→          return;
   165→        }
   166→
   167→        set((state) => ({
   168→          folders: {
   169→            ...state.folders,
   170→            [id]: {
   171→              ...folder,
   172→              ...updates,
   173→              updatedAt: new Date(),
   174→            },
   175→          },
   176→        }));
   177→        console.log('✅ Folder updated:', id);
   178→      },
   179→
   180→      deleteFolder: (id, deleteNotes = false) => {
   181→        // CRITICAL: Handle notes before deleting folder to prevent orphaned notes
   182→        // Get the folder being deleted
   183→        const folder = get().folders[id];
   184→        if (!folder) {
   185→          console.warn(`Folder ${id} not found`);
   186→          return;
   187→        }
   188→
   189→        // Get all descendant folders
   190→        const descendants = get()
   191→          .getFlatTree()
   192→          .filter((f) => get().isDescendantOf(f.id, id));
   193→
   194→        // Get all folder IDs that will be deleted (this folder + descendants)
   195→        const foldersToDelete = [id, ...descendants.map(d => d.id)];
   196→
   197→        // Handle notes in deleted folders
   198→        try {
   199→          // Import Notes store dynamically to avoid circular dependencies
   200→          const { useNotesStore } = require('./useNotesStore');
   201→          const notesStore = useNotesStore.getState();
   202→
   203→          // Get all notes in folders that will be deleted
   204→          const notesInDeletedFolders = notesStore.getAllNotes()
   205→            .filter((note: { folderId: string | null }) =>
   206→              note.folderId && foldersToDelete.includes(note.folderId)
   207→            );
   208→
   209→          if (notesInDeletedFolders.length > 0) {
   210→            if (deleteNotes) {
   211→              // Delete all notes in folder and descendants
   212→              const noteIds = notesInDeletedFolders.map((n: { id: string }) => n.id);
   213→              notesStore.deleteNotes(noteIds);
   214→              console.log(`🗑️ Deleted ${noteIds.length} notes from deleted folders`);
   215→            } else {
   216→              // Move notes to parent folder (or root if no parent)
   217→              const newFolderId = folder.parentId || null;
   218→              const noteIds = notesInDeletedFolders.map((n: { id: string }) => n.id);
   219→              notesStore.moveNotesToFolder(noteIds, newFolderId);
   220→              console.log(`📁 Moved ${noteIds.length} notes to ${newFolderId ? `folder ${newFolderId}` : 'root'}`);
   221→            }
   222→          }
   223→        } catch (error) {
   224→          console.error('Error handling notes in deleted folder:', error);
   225→          // Continue with folder deletion even if note handling fails
   226→        }
   227→
   228→        // Now safe to delete folders
   229→        set((state) => {
   230→          const { [id]: deleted, ...remainingFolders } = state.folders;
   231→
   232→          // Also delete descendants
   233→          descendants.forEach((desc) => {
   234→            delete remainingFolders[desc.id];
   235→          });
   236→
   237→          // Remove from expanded set
   238→          const newExpanded = new Set(state.expandedFolderIds);
   239→          newExpanded.delete(id);
   240→          descendants.forEach((desc) => newExpanded.delete(desc.id));
   241→
   242→          return {
   243→            folders: remainingFolders,
   244→            expandedFolderIds: newExpanded,
   245→            activeFolderId: state.activeFolderId === id ? null : state.activeFolderId,
   246→          };
   247→        });
   248→
   249→        console.log(`✅ Folder deleted: ${id} (${descendants.length} descendants)`);
   250→      },
   251→
   252→      duplicateFolder: (id) => {
   253→        const original = get().folders[id];
   254→        if (!original) {
   255→          console.warn(`Folder ${id} not found`);
   256→          return null;
   257→        }
   258→
   259→        const duplicate = createDefaultFolder({
   260→          ...original,
   261→          name: `${original.name} (Copy)`,
   262→        });
   263→
   264→        set((state) => ({
   265→          folders: {
   266→            ...state.folders,
   267→            [duplicate.id]: duplicate,
   268→          },
   269→        }));
   270→
   271→        console.log('✅ Folder duplicated:', id, '→', duplicate.id);
   272→        return duplicate;
   273→      },
   274→
   275→      // Hierarchy operations
   276→      moveFolder: (folderId, newParentId) => {
   277→        if (!get().canMoveFolder(folderId, newParentId)) {
   278→          console.warn(`Cannot move folder ${folderId} to ${newParentId}`);
   279→          return;
   280→        }
   281→
   282→        const folder = get().folders[folderId];
   283→        if (!folder) return;
   284→
   285→        set((state) => ({
   286→          folders: {
   287→            ...state.folders,
   288→            [folderId]: {
   289→              ...folder,
   290→              parentId: newParentId,
   291→              updatedAt: new Date(),
   292→            },
   293→          },
   294→        }));
   295→
   296→        console.log(`✅ Moved folder ${folderId} to parent ${newParentId}`);
   297→      },
   298→
   299→      getChildren: (parentId) => {
   300→        return Object.values(get().folders)
   301→          .filter((f) => f.parentId === parentId)
   302→          .sort((a, b) => a.name.localeCompare(b.name)); // Sort alphabetically
   303→      },
   304→
   305→      getParent: (folderId) => {
   306→        const folder = get().folders[folderId];
   307→        if (!folder || !folder.parentId) return null;
   308→        return get().folders[folder.parentId] || null;
   309→      },
   310→
   311→      getPath: (folderId) => {
   312→        const path: Folder[] = [];
   313→        let current: Folder | undefined = get().folders[folderId];
   314→
   315→        while (current) {
   316→          path.unshift(current);
   317→          current = current.parentId ? get().folders[current.parentId] : undefined;
   318→        }
   319→
   320→        return path;
   321→      },
   322→
   323→      getDepth: (folderId) => {
   324→        if (!folderId) return 0;
   325→
   326→        let depth = 0;
   327→        let current = get().folders[folderId];
   328→
   329→        while (current?.parentId) {
   330→          depth++;
   331→          current = get().folders[current.parentId];
   332→
   333→          // Prevent infinite loops
   334→          if (depth > 100) {
   335→            console.error('Circular folder reference detected!');
   336→            return depth;
   337→          }
   338→        }
   339→
   340→        return depth;
   341→      },
   342→
   343→      getFlatTree: () => {
   344→        return Object.values(get().folders).sort((a, b) =>
   345→          a.name.localeCompare(b.name)
   346→        );
   347→      },
   348→
   349→      getTree: () => {
   350→        const folders = Object.values(get().folders);
   351→
   352→        // Get real note counts from Notes store
   353→        const notesCountMap: Record<string, number> = {};
   354→        try {
   355→          // Import Notes store dynamically to avoid circular dependencies
   356→          const { useNotesStore } = require('./useNotesStore');
   357→          const notes = useNotesStore.getState().getAllNotes();
   358→
   359→          // Count notes per folder (excluding archived notes)
   360→          notes
   361→            .filter((note: { isArchived: boolean }) => !note.isArchived)
   362→            .forEach((note: { folderId: string | null }) => {
   363→              const folderId = note.folderId || 'root';
   364→              notesCountMap[folderId] = (notesCountMap[folderId] || 0) + 1;
   365→            });
   366→        } catch (error) {
   367→          console.error('Error getting note counts:', error);
   368→          // Continue with empty counts if Notes store not available
   369→        }
   370→
   371→        return buildTree(folders, null, 0, notesCountMap);
   372→      },
   373→
   374→      // Expand/Collapse
   375→      toggleExpanded: (id) => {
   376→        set((state) => {
   377→          const newExpanded = new Set(state.expandedFolderIds);
   378→          if (newExpanded.has(id)) {
   379→            newExpanded.delete(id);
   380→          } else {
   381→            newExpanded.add(id);
   382→          }
   383→          return { expandedFolderIds: newExpanded };
   384→        });
   385→        console.log(`✅ Toggled expand for folder: ${id}`);
   386→      },
   387→
   388→      expandFolder: (id) => {
   389→        set((state) => ({
   390→          expandedFolderIds: new Set([...state.expandedFolderIds, id]),
   391→        }));
   392→      },
   393→
   394→      collapseFolder: (id) => {
   395→        set((state) => {
   396→          const newExpanded = new Set(state.expandedFolderIds);
   397→          newExpanded.delete(id);
   398→          return { expandedFolderIds: newExpanded };
   399→        });
   400→      },
   401→
   402→      expandAll: () => {
   403→        const allIds = Object.keys(get().folders);
   404→        set({ expandedFolderIds: new Set(allIds) });
   405→        console.log('✅ Expanded all folders');
   406→      },
   407→
   408→      collapseAll: () => {
   409→        set({ expandedFolderIds: new Set() });
   410→        console.log('✅ Collapsed all folders');
   411→      },
   412→
   413→      expandPath: (folderId) => {
   414→        const path = get().getPath(folderId);
   415→        set((state) => {
   416→          const newExpanded = new Set(state.expandedFolderIds);
   417→          path.forEach((folder) => newExpanded.add(folder.id));
   418→          return { expandedFolderIds: newExpanded };
   419→        });
   420→        console.log(`✅ Expanded path to folder: ${folderId}`);
   421→      },
   422→
   423→      // UI state
   424→      setActiveFolder: (id) => {
   425→        set({ activeFolderId: id });
   426→        console.log('✅ Active folder set:', id);
   427→      },
   428→
   429→      // Utility
   430→      canMoveFolder: (folderId, targetParentId) => {
   431→        // Can't move to self
   432→        if (folderId === targetParentId) return false;
   433→
   434→        // Can't move to own descendant (would create cycle)
   435→        if (targetParentId && get().isDescendantOf(targetParentId, folderId)) {
   436→          return false;
   437→        }
   438→
   439→        // Check max depth
   440→        const newDepth = get().getDepth(targetParentId || '') + 1;
   441→        if (newDepth >= FOLDER_CONSTANTS.MAX_DEPTH) {
   442→          return false;
   443→        }
   444→
   445→        return true;
   446→      },
   447→
   448→      isDescendantOf: (folderId, ancestorId) => {
   449→        let current = get().folders[folderId];
   450→        let iterations = 0;
   451→
   452→        while (current?.parentId) {
   453→          if (current.parentId === ancestorId) return true;
   454→          current = get().folders[current.parentId];
   455→
   456→          // Prevent infinite loops
   457→          if (iterations++ > 100) {
   458→            console.error('Circular folder reference detected!');
   459→            return false;
   460→          }
   461→        }
   462→
   463→        return false;
   464→      },
   465→
   466→      exportFolders: () => {
   467→        return Object.values(get().folders);
   468→      },
   469→
   470→      importFolders: (folders, merge) => {
   471→        if (!merge) {
   472→          // Replace all folders
   473→          set({
   474→            folders: Object.fromEntries(folders.map((f) => [f.id, f])),
   475→            activeFolderId: null,
   476→            expandedFolderIds: new Set(),
   477→          });
   478→          console.log(`✅ Imported ${folders.length} folders (replace mode)`);
   479→        } else {
   480→          // Merge with existing folders
   481→          set((state) => {
   482→            const updatedFolders = { ...state.folders };
   483→            folders.forEach((folder) => {
   484→              updatedFolders[folder.id] = folder;
   485→            });
   486→            return { folders: updatedFolders };
   487→          });
   488→          console.log(`✅ Imported ${folders.length} folders (merge mode)`);
   489→        }
   490→      },
   491→
   492→      clearAllFolders: () => {
   493→        set({
   494→          folders: {},
   495→          activeFolderId: null,
   496→          expandedFolderIds: new Set(),
   497→        });
   498→        console.log('✅ All folders cleared');
   499→      },
   500→    }),
   501→    {
   502→      name: 'folders', // IndexedDB key
   503→      storage: createJSONStorage(() => createSyncedStorage()),
   504→      partialize: (state) => ({
   505→        // Only persist folders, not UI state
   506→        // Convert Set to Array for JSON serialization
   507→        folders: state.folders,
   508→        expandedFolderIds: Array.from(state.expandedFolderIds),
   509→      }),
   510→      // Handle date serialization and Set restoration
   511→      onRehydrateStorage: () => (state) => {
   512→        console.log('🔄 Folders store rehydrating...', state);
   513→        if (state) {
   514→          try {
   515→            // Convert date strings back to Date objects
   516→            if (state.folders && typeof state.folders === 'object') {
   517→              Object.values(state.folders).forEach((folder) => {
   518→                if (typeof folder.createdAt === 'string') {
   519→                  folder.createdAt = new Date(folder.createdAt);
   520→                }
   521→                if (typeof folder.updatedAt === 'string') {
   522→                  folder.updatedAt = new Date(folder.updatedAt);
   523→                }
   524→              });
   525→            } else {
   526→              state.folders = {};
   527→            }
   528→
   529→            // CRITICAL: Fix corrupted Set data
   530→            const expandedIds = (state as any).expandedFolderIds;
   531→            console.log('🔍 Checking expandedFolderIds type:', typeof expandedIds, expandedIds);
   532→
   533→            if (expandedIds instanceof Set) {
   534→              // Already a Set (shouldn't happen after persist, but just in case)
   535→              console.log('✅ expandedFolderIds is already a Set');
   536→            } else if (Array.isArray(expandedIds)) {
   537→              // Correct format from our partialize
   538→              state.expandedFolderIds = new Set(expandedIds);
   539→              console.log('✅ Converted array to Set:', state.expandedFolderIds);
   540→            } else {
   541→              // Corrupted data - plain object or other
   542→              console.warn('⚠️ Corrupted expandedFolderIds detected, resetting to empty Set');
   543→              state.expandedFolderIds = new Set<string>();
   544→            }
   545→          } catch (err) {
   546→            console.error('❌ Error during folders store rehydration:', err);
   547→            // Reset to safe defaults
   548→            state.folders = {};
   549→            state.expandedFolderIds = new Set<string>();
   550→            state.activeFolderId = null;
   551→          }
   552→        }
   553→        console.log('✅ Folders store rehydrated', state);
   554→      },
   555→    }
   556→  )
   557→);
   558→
   559→/**
   560→ * Selector hooks for optimized re-renders
   561→ */
   562→export const useActiveFolder = () =>
   563→  useFoldersStore((state) => {
   564→    const activeId = state.activeFolderId;
   565→    return activeId ? state.folders[activeId] : null;
   566→  });
   567→
   568→export const useFolderTree = () =>
   569→  useFoldersStore((state) => state.getTree());
   570→
   571→export const useFolderPath = (folderId: string) =>
   572→  useFoldersStore((state) => state.getPath(folderId));
   573→
   574→export const isFolderExpanded = (folderId: string) =>
   575→  useFoldersStore((state) => state.expandedFolderIds.has(folderId));
